class LegalEntity:
    def __init__(self, name, legal_personality=True):
        self.name = name
        self.legal_personality = legal_personality  # True for corporations, False for partnerships
        self.financial_positions = []

    def add_position(self, position_type, amount):
        self.financial_positions.append((position_type, amount))

    def set_off(self, other_entity, amount):
        # Set-off allows mutual debts to be offset against each other
        for pos1, pos2 in zip(self.financial_positions, other_entity.financial_positions):
            if (pos1[0] == 'debt' and pos2[0] == 'claim') or (pos1[0] == 'claim' and pos2[0] == 'debt'):
                if abs(pos1[1]) >= abs(pos2[1]):
                    self.financial_positions.remove(pos1)
                    other_entity.financial_positions.remove(pos2)
                    print(f"Set-off applied: {self.name} and {other_entity.name} offset debts of {pos2[1]}")
                    break

This snippet models legal personality (e.g., corporations) and set-off (mutual debt offsetting) as foundational concepts in financial law.
